import React, { useEffect, useMemo, useState } from 'react';
import './App.css';

const COLOR_COLUMNS = ['black', 'gray', 'blue', 'purple', 'green', 'brown', 'yellow', 'orange', 'red', 'pink', 'white'];
const normalizeColor = value => {
  const color = (value || '').trim().toLowerCase();
  return COLOR_COLUMNS.includes(color) ? color : 'gray';
}

function parseCharactersTxt(text) {
  if (!text.trim()) return [];
  return text
    .trim()
    .split(/\n[ \t]*\n/)
    .map(block => block.split('\n').map(line => line.trim()).filter(Boolean))
    .filter(lines => lines.length)
    .map(([name, ...raw]) => {
      const entries = [];
      for (let i = 0; i < raw.length; i += 1) {
        const charName = raw[i];
        if (!charName) continue;
        const maybeColor = normalizeColor(raw[i + 1]);
        const hasColor = COLOR_SET.has((raw[i + 1] || '').toLowerCase());
        entries.push({ name: charName, color: maybeColor });
        if (hasColor) i += 1;
      }
      return { name, entries };
    });
}

async function fetchScrapedImage(columnName, entry) {
  const query = `${columnName} ${entry} fanart`;

  try {
    const params = new URLSearchParams({ q: query });
    const res = await fetch(`/api/image-search?${params}`);
    const payload = await res.json().catch(() => ({}));

    if (!res.ok) return { ...EMPTY_IMAGE_RESULT, error: payload.error || 'Search failed' };
    return {
      imageUrl: payload.imageUrl ?? null,
      candidates: Array.isArray(payload.candidates) ? payload.candidates : [],
      error: null,
    };
  } catch {
    return { ...EMPTY_IMAGE_RESULT, error: 'Could not reach image search API' };
  }
}

class AppErrorBoundary extends React.Component {
  constructor(props) {
    super(props);
    this.state = { hasError: false };
  }

  static getDerivedStateFromError() {
    return { hasError: true };
  }

  render() {
    if (this.state.hasError) {
      return <div className="status error">Runtime error in UI. Reload the page.</div>;
    }
    return this.props.children;
  }
}

function CharacterCell({ columnName, entry }) {
  const [image, setImage] = useState(undefined);
  const [candidates, setCandidates] = useState([]);
  const [index, setIndex] = useState(0);
  const [loading, setLoading] = useState(false);
  const [open, setOpen] = useState(false);
  const [error, setError] = useState(null);

  const toggleOpen = async () => {
    const next = !open;
    setOpen(next);
    if (!next || image !== undefined) return;

    setLoading(true);
    const result = await fetchScrapedImage(columnName, entry.name);
    setImage(result.imageUrl);
    setCandidates(result.candidates);
    setIndex(0);
    setError(result.error);
    setLoading(false);
  };

  const showNextImage = event => {
    event.stopPropagation();
    if (!candidates.length) return;
    setIndex(prev => {
      const next = (prev + 1) % candidates.length;
      setImage(candidates[next]);
      setError(null);
      return next;
    });
  };

  return (
    <td className={`char-cell${open ? ' open' : ''}`} onClick={toggleOpen} title={open ? 'Click to collapse' : 'Click to reveal image'}>
      <span className="char-name">{entry.name}</span>
      <span className="char-color">{entry.color}</span>
      {open && (
        <div className="char-image">
          {loading ? (
            <div className="loading-text">Loadingâ€¦</div>
          ) : image ? (
            <>
              <img src={image} alt={`${columnName} - ${entry.name}`} />
              {candidates.length > 1 && (
                <button type="button" className="next-image-btn" onClick={showNextImage}>
                  Wrong image? Try next ({index + 1}/{candidates.length})
                </button>
              )}
            </>
          ) : (
            <div className="no-image">{error || 'No image found'}</div>
          )}
        </div>
      )}
    </td>
  );
}

function AppContent() {
  const [activeTab, setActiveTab] = useState('gallery');
  const [columns, setColumns] = useState([]);
  const [rawText, setRawText] = useState('');
  const [editorText, setEditorText] = useState('');
  const [error, setError] = useState(null);
  const [loading, setLoading] = useState(true);
  const [saveStatus, setSaveStatus] = useState('idle');

  const loadCharacters = async () => {
    setLoading(true);
    setError(null);
    try {
      const res = await fetch('/api/characters');
      if (!res.ok) throw new Error(`Could not load characters.txt (${res.status})`);
      const text = await res.text();
      setRawText(text);
      setEditorText(text);
      setColumns(parseCharactersTxt(text));
    } catch (e) {
      setError(e.message);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { loadCharacters(); }, []);

  const handleSave = async () => {
    setSaveStatus('saving');
    try {
      const res = await fetch('/api/characters', {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ content: editorText }),
      });

      if (!res.ok) {
        throw new Error(`Save failed (${res.status})`);
      }

      setRawText(editorText);
      setColumns(parseCharactersTxt(editorText));
      setSaveStatus('saved');
      setTimeout(() => setSaveStatus('idle'), 1200);
    } catch {
      setSaveStatus('error');
    }
  };

  if (loading) return <div className="status">Loadingâ€¦</div>;
  if (error) return <div className="status error">{error}</div>;

  const hasUnsavedChanges = editorText !== rawText;
  const maxRows = useMemo(() => Math.max(0, ...columns.map(c => c.entries.length)), [columns]);
  const groupedByColor = useMemo(() => {
    const grouped = Object.fromEntries(COLOR_COLUMNS.map(color => [color, []]));
    for (const column of columns) {
      for (const entry of column.entries) {
        grouped[normalizeColor(entry.color)].push({ ...entry, category: column.name });
      }
    }
    return grouped;
  }, [columns]);
  const colorRows = useMemo(() => Math.max(0, ...COLOR_COLUMNS.map(color => groupedByColor[color]?.length || 0)), [groupedByColor]);

  return (
    <div className="app">
      <h1>Character Gallery</h1>
      <p className="hint">Add a color below each character: black, gray, blue, purple, green, brown, yellow, orange, red, pink, white</p>

      <div className="tabs">
        {[
          ['gallery', 'Gallery'],
          ['colors', 'Color Sort'],
          ['editor', 'Edit chars.txt'],
        ].map(([key, label]) => (
          <button key={key} type="button" className={`tab-btn${activeTab === key ? ' active' : ''}`} onClick={() => setActiveTab(key)}>
            {label}
          </button>
        ))}
      </div>

      {activeTab === 'gallery' ? (
        <div className="table-wrapper">
          <table>
            <thead>
              <tr>
                {columns.map(col => (
                  <th key={col.name}>{col.name}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {Array.from({ length: maxRows }, (_, i) => (
                <tr key={i}>
                  {columns.map(col =>
                    col.entries[i] ? (
                      <CharacterCell key={col.name} columnName={col.name} entry={col.entries[i]} />
                    ) : (
                      <td key={col.name} className="empty-cell" />
                    )
                  )}
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      ) : activeTab === 'colors' ? (
        <div className="table-wrapper color-table-wrap">
          <table className="color-table">
            <thead>
              <tr>
                {COLOR_COLUMNS.map(color => (
                  <th key={color} className={`color-col-head color-${color}`}>{color}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {Array.from({ length: colorRows }, (_, rowIndex) => (
                <tr key={rowIndex}>
                  {COLOR_COLUMNS.map(color => {
                    const item = (groupedByColor[color] || [])[rowIndex];
                    return (
                      <td key={`${color}-${rowIndex}`} className={`color-cell color-${color}`}>
                        {item ? (
                          <>
                            <span className="color-name">{item.name}</span>
                            <span className="color-category">{item.category}</span>
                          </>
                        ) : null}
                      </td>
                    );
                  })}
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      ) : (
        <div className="editor-panel">
          <textarea
            value={editorText}
            onChange={e => setEditorText(e.target.value)}
            spellCheck={false}
            aria-label="Edit characters text"
          />
          <div className="editor-actions">
            <button type="button" onClick={handleSave} disabled={!hasUnsavedChanges || saveStatus === 'saving'}>
              {saveStatus === 'saving' ? 'Saving...' : 'Save chars.txt'}
            </button>
            <button type="button" onClick={loadCharacters}>Reload from disk</button>
            {saveStatus === 'saved' && <span className="save-ok">Saved.</span>}
            {saveStatus === 'error' && <span className="save-error">Save failed.</span>}
          </div>
        </div>
      )}
    </div>
  );
}

export default function App() {
  return (
    <AppErrorBoundary>
      <AppContent />
    </AppErrorBoundary>
  );
}
